using System.Text.RegularExpressions;

namespace QuickCode.Demo.Application.Contracts;

public static class StringCaseExtensions
{
    public static string PascalToKebabCase(this string value)
    {
        if (string.IsNullOrEmpty(value))
            return value;

        return Regex.Replace(
                value,
                "(?<!^)([A-Z][a-z]|(?<=[a-z])[A-Z0-9])",
                "-$1",
                RegexOptions.Compiled)
            .Trim()
            .ToLower();
    }

    public static string KebabCaseToPascal(this string value, string joinString = " ")
    {
        if (string.IsNullOrEmpty(value))
            return value;

        return string.Join(joinString, value.Split('-').Select(FirstCharToUpper));
    }

    private static string FirstCharToUpper(string input) =>
        input switch
        {
            null => throw new ArgumentNullException(nameof(input)),
            "" => throw new ArgumentException($"{nameof(input)} cannot be empty", nameof(input)),
            _ => string.Concat(input[0].ToString().ToUpper(), input.AsSpan(1))
        };
}
